<span class="line"><span style="color:#CDD6F4;">    module </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> importlib</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">import_module</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">module_name</span><span style="color:#9399B2;">)</span></span>
